import { useState, useEffect } from 'react'
import { PlanType, PLAN_CONFIG, SubscriptionPlan } from '../types'
import { useAuth } from '../contexts/AuthContext'
import { PlanTypeEnum } from '../types/enums'

export const usePlan = () => {
  const { subscription } = useAuth()
  const initialPlan = (subscription?.planType || PlanTypeEnum.SILVER) as PlanType
  const [currentPlan, setCurrentPlan] = useState<PlanType>(initialPlan)
  const [planConfig, setPlanConfig] = useState<SubscriptionPlan>(PLAN_CONFIG[initialPlan])

  useEffect(() => {
    setPlanConfig(PLAN_CONFIG[currentPlan])
  }, [currentPlan])

  useEffect(() => {
    if (subscription?.planType) {
      setCurrentPlan(subscription.planType)
    }
  }, [subscription?.planType])

  const hasFeature = (feature: keyof typeof planConfig.features): boolean => {
    return planConfig.features[feature]
  }

  const isGoldPlan = currentPlan === 'gold'
  const isSilverPlan = currentPlan === 'silver'

  return {
    currentPlan,
    planConfig,
    hasFeature,
    isGoldPlan,
    isSilverPlan,
  }
}
