// Payment In/Out Service
// Handle direct payment receipts and payments (not tied to invoices)

import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDocs,
  query,
  where
} from 'firebase/firestore'
import { db, COLLECTIONS, isFirebaseReady } from './firebase'
import { getCurrentCompanyId, getScopedStorageKey } from '../utils/authUtils'
import { invalidateCacheByPrefix } from '../utils/cacheUtils'
import { DATA_EVENTS, emitDataEvent } from '../utils/dataEvents'

// Types
export interface PaymentIn {
  id: string
  partyId: string
  partyName: string
  amount: number
  paymentMode: 'cash' | 'upi' | 'bank' | 'cheque' | 'card'
  paymentDate: string
  reference?: string
  notes?: string
  createdAt: string
  companyId?: string
}

export interface PaymentOut {
  id: string
  partyId: string
  partyName: string
  amount: number
  paymentMode: 'cash' | 'upi' | 'bank' | 'cheque' | 'card'
  paymentDate: string
  reference?: string
  notes?: string
  createdAt: string
  companyId?: string
}

const PAYMENTS_IN_KEY_BASE = 'thisai_crm_payments_in'
const PAYMENTS_OUT_KEY_BASE = 'thisai_crm_payments_out'

const getPaymentsInStorageKey = () => getScopedStorageKey(PAYMENTS_IN_KEY_BASE, 'company')
const getPaymentsOutStorageKey = () => getScopedStorageKey(PAYMENTS_OUT_KEY_BASE, 'company')

const getLegacyPaymentsInKey = () => PAYMENTS_IN_KEY_BASE
const getLegacyPaymentsOutKey = () => PAYMENTS_OUT_KEY_BASE

const generateId = (prefix: string) =>
  `${prefix}_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`

// Duplicate-submit guards for slow UI/network conditions.
// Prevents duplicate Payment In/Out records when users click "Save" repeatedly.
const PAYMENT_INOUT_CREATE_DEDUP_WINDOW_MS = 8000
const inFlightPaymentInCreateKeys = new Map<string, Promise<PaymentIn>>()
const recentCreatedPaymentsIn = new Map<string, { payment: PaymentIn; timestamp: number }>()
const inFlightPaymentOutCreateKeys = new Map<string, Promise<PaymentOut>>()
const recentCreatedPaymentsOut = new Map<string, { payment: PaymentOut; timestamp: number }>()

const normalizePaymentInOutDedupPart = (value: unknown): string =>
  String(value ?? '').trim().toLowerCase()

const normalizeMoneyForPaymentInOutDedup = (value: unknown): string => {
  const n = Number(value)
  if (!Number.isFinite(n)) return '0.00'
  return (Math.round(n * 100) / 100).toFixed(2)
}

const buildPaymentInDedupKey = (data: Partial<PaymentIn>, companyId: string) => {
  return [
    companyId,
    'in',
    normalizePaymentInOutDedupPart((data as any).partyId),
    normalizeMoneyForPaymentInOutDedup((data as any).amount),
    normalizePaymentInOutDedupPart((data as any).paymentMode),
    normalizePaymentInOutDedupPart((data as any).paymentDate),
    normalizePaymentInOutDedupPart((data as any).reference),
  ].join('|')
}

const buildPaymentOutDedupKey = (data: Partial<PaymentOut>, companyId: string) => {
  return [
    companyId,
    'out',
    normalizePaymentInOutDedupPart((data as any).partyId),
    normalizeMoneyForPaymentInOutDedup((data as any).amount),
    normalizePaymentInOutDedupPart((data as any).paymentMode),
    normalizePaymentInOutDedupPart((data as any).paymentDate),
    normalizePaymentInOutDedupPart((data as any).reference),
  ].join('|')
}

const purgeRecentPaymentsInOut = () => {
  const now = Date.now()
  for (const [key, entry] of recentCreatedPaymentsIn.entries()) {
    if (now - entry.timestamp > PAYMENT_INOUT_CREATE_DEDUP_WINDOW_MS) {
      recentCreatedPaymentsIn.delete(key)
    }
  }
  for (const [key, entry] of recentCreatedPaymentsOut.entries()) {
    if (now - entry.timestamp > PAYMENT_INOUT_CREATE_DEDUP_WINDOW_MS) {
      recentCreatedPaymentsOut.delete(key)
    }
  }
}

const invalidatePaymentInOutRelatedCaches = () => {
  // These payments affect party outstanding, so clear cached outstanding results.
  invalidateCacheByPrefix('parties_outstanding_')

  // Notify mounted pages (Parties screen listens to these).
  emitDataEvent(DATA_EVENTS.PAYMENTS_CHANGED, { reason: 'payment-in-out' })
  emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'payment-in-out' })
}

function readArrayFromStorage<T>(key: string): T[] {
  try {
    const stored = localStorage.getItem(key)
    const parsed = stored ? JSON.parse(stored) : []
    return Array.isArray(parsed) ? parsed : []
  } catch {
    return []
  }
}

function mergeById<T extends { id: string }>(a: T[], b: T[]): T[] {
  const map = new Map<string, T>()
  for (const item of a) map.set(item.id, item)
  for (const item of b) map.set(item.id, item)
  return Array.from(map.values())
}

function sortByCreatedAtDesc<T extends { createdAt?: string }>(items: T[]): T[] {
  items.sort((a, b) => (b.createdAt || '').localeCompare(a.createdAt || ''))
  return items
}

function getPaymentsInFromScopedLocalStorage(): PaymentIn[] {
  return readArrayFromStorage<PaymentIn>(getPaymentsInStorageKey())
}

function getPaymentsOutFromScopedLocalStorage(): PaymentOut[] {
  return readArrayFromStorage<PaymentOut>(getPaymentsOutStorageKey())
}

function getPaymentsInFromLocalStorage(): PaymentIn[] {
  const scopedKey = getPaymentsInStorageKey()
  const scoped = readArrayFromStorage<PaymentIn>(scopedKey)
  const legacyKey = getLegacyPaymentsInKey()
  const legacy = legacyKey === scopedKey ? [] : readArrayFromStorage<PaymentIn>(legacyKey)
  return mergeById(scoped, legacy)
}

function getPaymentsOutFromLocalStorage(): PaymentOut[] {
  const scopedKey = getPaymentsOutStorageKey()
  const scoped = readArrayFromStorage<PaymentOut>(scopedKey)
  const legacyKey = getLegacyPaymentsOutKey()
  const legacy = legacyKey === scopedKey ? [] : readArrayFromStorage<PaymentOut>(legacyKey)
  return mergeById(scoped, legacy)
}

// ==================== PAYMENT IN ====================

export async function createPaymentIn(data: Omit<PaymentIn, 'id' | 'createdAt'>): Promise<PaymentIn> {
  const companyId = getCurrentCompanyId() || ''
  if (!companyId) {
    // No company context: fall back to original behavior (no dedup).
    return createPaymentInUnsafe(data)
  }

  const dedupKey = buildPaymentInDedupKey(data as any, companyId)
  purgeRecentPaymentsInOut()

  const recent = recentCreatedPaymentsIn.get(dedupKey)
  if (recent && Date.now() - recent.timestamp < PAYMENT_INOUT_CREATE_DEDUP_WINDOW_MS) {
    return recent.payment
  }

  const existingInFlight = inFlightPaymentInCreateKeys.get(dedupKey)
  if (existingInFlight) {
    return existingInFlight
  }

  const promise = createPaymentInUnsafe(data)
  inFlightPaymentInCreateKeys.set(dedupKey, promise)
  try {
    const created = await promise
    recentCreatedPaymentsIn.set(dedupKey, { payment: created, timestamp: Date.now() })
    return created
  } finally {
    inFlightPaymentInCreateKeys.delete(dedupKey)
  }
}

async function createPaymentInUnsafe(data: Omit<PaymentIn, 'id' | 'createdAt'>): Promise<PaymentIn> {
  const now = new Date().toISOString()
  const id = generateId('PIN')
  const companyId = getCurrentCompanyId() || undefined

  const newPayment: PaymentIn = {
    ...data,
    id,
    createdAt: now,
    companyId
  }

  // Save to localStorage first (scoped)
  const payments = getPaymentsInFromScopedLocalStorage()
  payments.push(newPayment)
  localStorage.setItem(getPaymentsInStorageKey(), JSON.stringify(payments))
  invalidatePaymentInOutRelatedCaches()

  // Sync to Firebase if available
  if (isFirebaseReady() && db) {
    try {
      const docRef = await addDoc(collection(db, COLLECTIONS.PAYMENTS_IN), {
        ...data,
        createdAt: now,
        companyId: companyId || null
      })

      // Update local record with Firebase ID
      const updatedPayment = { ...newPayment, id: docRef.id }
      const updatedPayments = payments.map(p => (p.id === id ? updatedPayment : p))
      localStorage.setItem(getPaymentsInStorageKey(), JSON.stringify(updatedPayments))
      invalidatePaymentInOutRelatedCaches()

      console.log('[PaymentIn] Saved to Firebase:', docRef.id)
      return updatedPayment
    } catch (error) {
      console.error('[PaymentIn] Firebase save failed, kept in localStorage:', error)
    }
  }

  return newPayment
}

export async function getPaymentsIn(): Promise<PaymentIn[]> {
  const companyId = getCurrentCompanyId()

  // Try Firebase first if available
  if (isFirebaseReady() && db) {
    try {
      const baseRef = collection(db, COLLECTIONS.PAYMENTS_IN)
      const q = companyId ? query(baseRef, where('companyId', '==', companyId)) : baseRef
      const snapshot = await getDocs(q)
      const payments = snapshot.docs.map(d => ({
        id: d.id,
        ...(d.data() as any)
      } as PaymentIn))

      sortByCreatedAtDesc(payments)

      // Update local cache (scoped)
      localStorage.setItem(getPaymentsInStorageKey(), JSON.stringify(payments))

      return payments
    } catch (error) {
      console.error('[PaymentIn] Firebase fetch failed:', error)
    }
  }

  // Fallback to localStorage (scoped + legacy merge)
  return sortByCreatedAtDesc(getPaymentsInFromLocalStorage())
}

export async function deletePaymentIn(id: string): Promise<boolean> {
  // Remove from localStorage (scoped + legacy)
  const scopedKey = getPaymentsInStorageKey()
  const legacyKey = getLegacyPaymentsInKey()

  const scoped = readArrayFromStorage<PaymentIn>(scopedKey).filter(p => p.id !== id)
  localStorage.setItem(scopedKey, JSON.stringify(scoped))

  if (legacyKey !== scopedKey) {
    const legacy = readArrayFromStorage<PaymentIn>(legacyKey).filter(p => p.id !== id)
    localStorage.setItem(legacyKey, JSON.stringify(legacy))
  }

  invalidatePaymentInOutRelatedCaches()

  // Delete from Firebase if available
  if (isFirebaseReady() && db && !id.startsWith('PIN_')) {
    try {
      await deleteDoc(doc(db, COLLECTIONS.PAYMENTS_IN, id))
      console.log('[PaymentIn] Deleted from Firebase:', id)
      invalidatePaymentInOutRelatedCaches()
    } catch (error) {
      console.error('[PaymentIn] Firebase delete failed:', error)
    }
  }

  return true
}

// ==================== PAYMENT OUT ====================

